# Mead.Elv &lt;- read.csv("https://www.usbr.gov/uc/water/hydrodata/reservoir_data/921/csv/49.csv")
# write.csv(Mead.Elv, "Data/mead_elevation.csv")

# Powell.Elv &lt;- read.csv("https://www.usbr.gov/uc/water/hydrodata/reservoir_data/919/csv/49.csv")
# write.csv(Powell.Elv, "Data/powell_elevation.csv")


mead_raw = await d3.csv("../../Data/mead_elevation.csv")
powell_raw = await d3.csv("../../Data/powell_elevation.csv")

// Parse and label each dataset
mead = mead_raw.map(d =&gt; ({
  date: new Date(d.datetime),
  year: +d.datetime.substring(0, 4),
  elevation: +d["pool elevation"],
  reservoir: "Lake Mead"
})).filter(d =&gt; !isNaN(d.elevation))

powell = powell_raw.map(d =&gt; ({
  date: new Date(d.datetime),
  year: +d.datetime.substring(0, 4),
  elevation: +d["pool elevation"],
  reservoir: "Lake Powell"
})).filter(d =&gt; !isNaN(d.elevation))

// Combine and average by year
all_data = [...mead, ...powell]

yearly = d3.rollups(
  all_data,
  v =&gt; d3.mean(v, d =&gt; d.elevation),
  d =&gt; d.reservoir,
  d =&gt; d.year
).flatMap(([reservoir, years]) =&gt;
  years.map(([year, elevation]) =&gt; ({ reservoir, year, elevation }))
)












































viewof reservoir_choice = Inputs.select(
  ["Lake Mead", "Lake Powell", "Both"],
  { label: "Reservoir:", value: "Both" }
)

// Filter data based on selection
filtered = reservoir_choice === "Both"
  ? yearly
  : yearly.filter(d =&gt; d.reservoir === reservoir_choice)
















Plot.plot({
  title: "Average Annual Reservoir Elevation",
  width: 700,
  height: 400,
  x: { label: "Year", tickFormat: "d" },
  y: { label: "Elevation (ft)" },
  color: { legend: true },
  marks: [
    Plot.lineY(filtered, {
      x: "year",
      y: "elevation",
      stroke: "reservoir",
      strokeWidth: 2,
      tip: true
    }),
    Plot.dotY(filtered, {
      x: "year",
      y: "elevation",
      stroke: "reservoir",
      r: 2
    })
  ]
})
